def verify_signature(payload: bytes, signature_header: str, secret: str) -> bool:
    """Verify HMAC-SHA256 signature from payment provider."""
    if not secret:
        logging.warning("PAYMENT_WEBHOOK_SECRET is not configured")
        return False

    if not signature_header:
        return False

    # Support common signature formats: "sha256=<hex>" or raw hex
    signature = signature_header
    if signature.startswith("sha256="):
        signature = signature[7:]
    elif signature.startswith("v1="):
        signature = signature[3:]

    expected = hmac.new(
        secret.encode("utf-8"),
        payload,
        hashlib.sha256
    ).hexdigest()

    return hmac.compare_digest(expected.lower(), signature.lower())


def validate_timestamp(timestamp_header: Optional[str]) -> bool:
    """Prevent replay attacks by validating request timestamp."""
    if not timestamp_header:
        # If provider doesn't send timestamps, skip this check
        # but log a warning
        logging.warning("No timestamp header provided; replay protection reduced")
        return True

    try:
        request_time = int(timestamp_header)
    except (ValueError, TypeError):
        try:
            from datetime import datetime
            dt = datetime.fromisoformat(timestamp_header.replace("Z", "+00:00"))
            request_time = int(dt.timestamp())
        except (ValueError, TypeError):
            logging.warning("Invalid timestamp format: %s", timestamp_header)
            return False

    current_time = int(time.time())
    drift = abs(current_time - request_time)

    if drift > REPLAY_WINDOW_SECONDS:
        logging.warning(
            "Request timestamp too old or too far in future: drift=%ds, max=%ds",
            drift, REPLAY_WINDOW_SECONDS
        )
        return False

    return True


def check_idempotency(event_id: Optional[str]) -> bool:
    """Check if this event has already been processed (idempotency / replay prevention)."""
    if not event_id:
        return True  # No event ID provided; allow but log

    current_time = time.time()

    # Clean up old entries
    expired_keys = [
        k for k, v in _processed_event_ids.items()
        if current_time - v > REPLAY_WINDOW_SECONDS * 2
    ]
    for k in expired_keys:
        del _processed_event_ids[k]

    if event_id in _processed_event_ids:
        logging.warning("Duplicate event detected: %s", event_id)
        return False

    _processed_event_ids[event_id] = current_time
    return True


def validate_ip(request: func.HttpRequest) -> bool:
    """Validate the request comes from an allowed IP range."""
    if not ALLOWED_IPS or ALLOWED_IPS == [""]:
        logging.warning("ALLOWED_PROVIDER_IPS not configured; skipping IP validation")
        return True

    # Azure Functions behind a load balancer: check X-Forwarded-For
    client_ip = request.headers.get("X-Forwarded-For", "").split(",")[0].strip()
    if not client_ip:
        client_ip = request.headers.get("X-Real-IP", "").strip()
    if not client_ip:
        # Fallback - may not be available in all environments
        client_ip = request.headers.get("REMOTE_ADDR", "unknown")

    allowed = [ip.strip() for ip in ALLOWED_IPS if ip.strip()]
    if client_ip not in allowed:
        logging.warning("Request from unauthorized IP: %s", client_ip)
        return False

    return True


def sanitize_string(value: str, max_length: int = 256) -> str:
    """Sanitize string input to prevent injection attacks."""
    if not isinstance(value, str):
        return ""
    # Truncate
    value = value[:max_length]
    # Remove control characters except common whitespace
    value = re.sub(r'[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]', '', value)
    return value


